# Fibonacci function with memoization and kill switch

def fibonacci(n, kill_switch=False):
    memo = {0: 0, 1: 1}

    def fib(n):
        if n in memo:
            return memo[n]
        if n > 1:
            result = fib(n-1) + fib(n-2)
            memo[n] = result
            return result
        else:
            return n

    if kill_switch:
        raise SystemExit("Kill switch activated.")
    return fib(n)

